parameters.query:
SELECT u.profile, u.language,
  (SELECT json_agg(json_build_object('id', s.id, 'config', s.config)) FROM schemes s WHERE s.active) AS schemes
FROM users u WHERE u.id = $1;

parameters.jsCode:
// ===== Deterministic eligibility engine — zero LLM tokens =====
const trig = $('Matcher Trigger').first().json;
const { profile = {}, schemes = [], language = 'hi' } = $json;
const ops = {
  eq:  (a, b) => String(a).toLowerCase() === String(b).toLowerCase(),
  neq: (a, b) => String(a).toLowerCase() !== String(b).toLowerCase(),
  gte: (a, b) => Number(a) >= Number(b),
  lte: (a, b) => Number(a) <= Number(b),
  in:  (a, b) => Array.isArray(b) && b.map(x => String(x).toLowerCase()).includes(String(a).toLowerCase()),
};
function evalNode(rule, prof, unknowns) {
  if (rule.all) return rule.all.every(r => evalNode(r, prof, unknowns));
  if (rule.any) return rule.any.some(r => evalNode(r, prof, unknowns));
  const v = prof[rule.field];
  if (v === undefined || v === null) { unknowns.push(rule.field); return true; }
  return ops[rule.op] ? ops[rule.op](v, rule.value) : false;
}
const results = (schemes || []).map(s => {
  const unknowns = [];
  const eligible = evalNode(s.config.eligibility || { all: [] }, profile, unknowns);
  const b = s.config.benefit || {};
  const amt = b.amount_inr || 0;
  let annual;
  if (b.type === 'monthly_cash') annual = amt * 12;
  else if (b.type === 'insurance_cover') annual = amt * 0.01;
  else annual = amt;
  const effort = s.config.effort_score || 3;
  return { id: s.id, name: s.config.name, benefit: s.config.benefit,
           eligible, unknown_fields: [...new Set(unknowns)], score: annual / effort };
});
const matches = results.filter(r => r.eligible && r.unknown_fields.length === 0)
                       .sort((a, b) => b.score - a.score).slice(0, 3);
const needInfo = results.filter(r => r.eligible && r.unknown_fields.length > 0)
                        .sort((a, b) => b.score - a.score);
return [{ json: { user_id: trig.user_id, chat_id: trig.chat_id, language, profile, matches, need_info: needInfo } }];

const j = $json;
const unknown = j.need_info[0]?.unknown_fields?.[0];
const qs = {
  age: 'Aapki umar kitni hai?', gender: 'Aap mahila hain ya purush?',
  marital_status: 'Aapki vaivahik sthiti kya hai?',
  annual_income: 'Parivaar ki saalana aamdani lagbhag kitni hai?',
  category: 'Aapki shreni? (GEN/OBC/SC/ST)', district: 'Aapka zila?', state: 'Aapka rajya?'
};
const text = unknown
  ? `Ek jankari aur chahiye taaki main sahi yojana dhundh sakun: ${qs[unknown] || unknown}`
  : 'Abhi koi yojana match nahi hui. Apne baare mein thoda aur bataiye — umar, kaam, parivaar.';
return [{ json: { chat_id: j.chat_id, text } }];

const j = $json;
const summary = j.matches.map((m, i) => `${i + 1}. ${m.name?.hi || m.name?.en} — ${m.benefit?.type === 'monthly_cash' ? '₹' + m.benefit.amount_inr + '/mahina' : '₹' + (m.benefit?.amount_inr || '?')}`).join('
');
const prompt = `You are Haq, a warm plain-spoken assistant. Language: ${j.language === 'hi' ? 'Hindi (Devanagari)' : 'simple English'}.
Explain these scheme matches to a user who may not read well. Short sentences. Concrete amounts first. No jargon. Never promise approval; say they appear eligible. End with exactly one question: consent to apply for scheme #1 (tell them to reply HAAN / YES).
Matches:
${summary}`;
return [{ json: { ...j, body: { contents: [{ parts: [{ text: prompt }] }], generationConfig: { maxOutputTokens: 400 } } } }];

const ctx = $('Build Explainer').first().json;
const text = ($json.candidates?.[0]?.content?.parts?.[0]?.text || '').trim() || 'Aap in yojanaon ke liye paatr lagte hain.';
return [{ json: { chat_id: ctx.chat_id, user_id: ctx.user_id, top_scheme_id: ctx.matches[0].id, text } }];

